private fun computeIntrinsicSize(start: Painter?, end: Painter?): Size {
    val startSize = start?.intrinsicSize ?: Size.Zero
    val endSize = end?.intrinsicSize ?: Size.Zero

    val isStartSpecified = startSize.isSpecified
    val isEndSpecified = endSize.isSpecified

    if (preferEndFirstIntrinsicSize) {
        if (isEndSpecified) return endSize
        if (isStartSpecified) return startSize
    }

    if (isStartSpecified && isEndSpecified) {
        return Size(
            width = maxOf(startSize.width, endSize.width),
            height = maxOf(startSize.height, endSize.height),
        )
    }

    if (preferExactIntrinsicSize) {
        if (isStartSpecified) return startSize
        if (isEndSpecified) return endSize
    }
    return Size.Unspecified
}

private fun DrawScope.drawPainter(painter: Painter?, alpha: Float) {
    if (painter == null || alpha <= 0) return

    with(painter) {
        val size = size
        val drawSize = computeDrawSize(intrinsicSize, size)

        if (size.isUnspecified || size.isEmpty()) {
            draw(drawSize, alpha, colorFilter)
        } else {
            inset(
                horizontal = (size.width - drawSize.width) / 2,
                vertical = (size.height - drawSize.height) / 2,
            ) {
                draw(drawSize, alpha, colorFilter)
            }
        }
    }
}

override fun update(node: SubcomposeContentPainterNode) {
    val intrinsicsChanged = node.painter.intrinsicSize != painter.intrinsicSize

    node.painter = painter
    node.alignment = alignment
    node.contentScale = contentScale
    node.alpha = alpha
    node.colorFilter = colorFilter
    node.clipToBounds = clipToBounds

    if (node.contentDescription != contentDescription) {
        node.contentDescription = contentDescription
        node.invalidateSemantics()
    }

    // Only remeasure if intrinsics have changed.
    if (intrinsicsChanged) {
        node.invalidateMeasurement()
    }

    // Redraw because one of the node properties has changed.
    node.invalidateDraw()
}

private fun calculateScaledSize(dstSize: Size): Size {
    if (dstSize.isEmpty()) {
        return Size.Zero
    }

    val intrinsicSize = painter.intrinsicSize
    if (intrinsicSize.isUnspecified) {
        return dstSize
    }

    val srcSize = Size(
        width = intrinsicSize.width.takeOrElse { dstSize.width },
        height = intrinsicSize.height.takeOrElse { dstSize.height },
    )
    val scaleFactor = contentScale.computeScaleFactor(srcSize, dstSize)
    if (!scaleFactor.scaleX.isFinite() || !scaleFactor.scaleY.isFinite()) {
        return dstSize
    }

    return scaleFactor * srcSize
}

internal fun CoroutineScope.launchWithDeferredDispatch(
    block: suspend CoroutineScope.() -> Unit,
): Job {
    val originalDispatcher = coroutineContext.dispatcher
    if (originalDispatcher == null || originalDispatcher == Dispatchers.Unconfined) {
        return launch(
            context = Dispatchers.Unconfined,
            start = CoroutineStart.UNDISPATCHED,
            block = block,
        )
    } else {
        return CoroutineScope(DeferredDispatchCoroutineContext(coroutineContext)).launch(
            context = DeferredDispatchCoroutineDispatcher(originalDispatcher),
            start = CoroutineStart.UNDISPATCHED,
            block = block,
        )
    }
}

