private fun ImageDecoder.configureImageDecoderProperties() {
    onPartialImageListener = ImageDecoder.OnPartialImageListener { true }
    allocator = if (options.bitmapConfig.isHardware) {
        ImageDecoder.ALLOCATOR_HARDWARE
    } else {
        ImageDecoder.ALLOCATOR_SOFTWARE
    }
    memorySizePolicy = if (options.allowRgb565) {
        ImageDecoder.MEMORY_POLICY_LOW_RAM
    } else {
        ImageDecoder.MEMORY_POLICY_DEFAULT
    }
    if (options.colorSpace != null) {
        setTargetColorSpace(options.colorSpace)
    }
    isUnpremultipliedRequired = !options.premultipliedAlpha
}

override suspend fun fetch(): FetchResult {
    val isVector = data.isVector
    return ImageFetchResult(
        image = if (isVector) {
            DrawableUtils.convertToBitmap(
                drawable = data,
                config = options.bitmapConfig,
                size = options.size,
                scale = options.scale,
                maxSize = options.maxBitmapSize,
                allowInexactSize = options.precision == Precision.INEXACT,
            ).toDrawable(options.context)
        } else {
            data
        }.asImage(),
        isSampled = isVector,
        dataSource = DataSource.MEMORY,
    )
}

internal actual fun ComponentRegistry.Builder.addAndroidComponents(
    options: RealImageLoader.Options,
): ComponentRegistry.Builder = apply {
    // Mappers
    add(AndroidUriMapper())
    add(ResourceIntMapper())

    // Keyers
    add(AndroidResourceUriKeyer())

    // Fetchers
    add(AssetUriFetcher.Factory())
    add(ContentUriFetcher.Factory())
    add(ResourceUriFetcher.Factory())
    add(DrawableFetcher.Factory())

    // Decoders
    val parallelismLock = Semaphore(options.bitmapFactoryMaxParallelism)
    if (options.enableStaticImageDecoder()) {
        add(
            StaticImageDecoder.Factory(
                parallelismLock = parallelismLock,
            ),
        )
    }
    add(
        BitmapFactoryDecoder.Factory(
            parallelismLock = parallelismLock,
            exifOrientationStrategy = options.bitmapFactoryExifOrientationStrategy,
        ),
    )
}

override fun updateRequest(request: ImageRequest): ImageRequest {
    val builder = request.newBuilder()
        .defaults(imageLoader.defaults)

    var sizeResolver = request.defined.sizeResolver
    if (sizeResolver == null) {
        sizeResolver = request.resolveSizeResolver()
        builder.size(sizeResolver)
    }

    if (request.defined.scale == null) {
        builder.scale(request.resolveScale())
    }

    if (request.defined.precision == null) {
        builder.precision(request.resolvePrecision(sizeResolver))
    }

    return builder.build()
}

get() {
    var manager = getTag(R.id.coil3_request_manager) as? ViewTargetRequestManager
    if (manager == null) {
        manager = synchronized(this) {
            // Check again in case the request manager was just set.
            (getTag(R.id.coil3_request_manager) as? ViewTargetRequestManager)
                ?.let { return@synchronized it }

            ViewTargetRequestManager(this).apply {
                addOnAttachStateChangeListener(this)
                setTag(R.id.coil3_request_manager, this)
            }
        }
    }
    return manager
}

@Synchronized
    fun getDisposable(job: Deferred<ImageResult>): ViewTargetDisposable {
        // If this is a restarted request, update the current disposable and return it.
        val disposable = currentDisposable
        if (disposable != null && isMainThread() && isRestart) {
            isRestart = false
            disposable.job = job
            return disposable
        }

        // Cancel any pending clears since they were for the previous request.
        pendingClear?.cancel()
        pendingClear = null

        // Create a new disposable as this is a new request.
        return ViewTargetDisposable(view, job).also { currentDisposable = it }
    }

private fun calculateOutputSize(input: Bitmap, size: Size): IntPair {
    if (size.isOriginal) {
        return IntPair(input.width, input.height)
    }

    val (dstWidth, dstHeight) = size
    if (dstWidth is Dimension.Pixels && dstHeight is Dimension.Pixels) {
        return IntPair(dstWidth.px, dstHeight.px)
    }

    val multiplier = DecodeUtils.computeSizeMultiplier(
        srcWidth = input.width,
        srcHeight = input.height,
        dstWidth = size.width.pxOrElse { Int.MIN_VALUE },
        dstHeight = size.height.pxOrElse { Int.MIN_VALUE },
        scale = Scale.FILL,
        maxSize = Size.ORIGINAL,
    )
    val outputWidth = (multiplier * input.width).roundToInt()
    val outputHeight = (multiplier * input.height).roundToInt()
    return IntPair(outputWidth, outputHeight)
}

