private fun isSizeValid(
    allowInexactSize: Boolean,
    bitmap: Bitmap,
    size: Size,
    scale: Scale,
    maxSize: Size,
): Boolean {
    if (allowInexactSize) {
        // Any size is valid.
        return true
    } else {
        // The bitmap must match the scaled dimensions of the destination exactly.
        val (dstWidth, dstHeight) = DecodeUtils.computeDstSize(
            srcWidth = bitmap.width,
            srcHeight = bitmap.height,
            targetSize = size,
            scale = scale,
            maxSize = maxSize,
        )
        return DecodeUtils.computeSizeMultiplier(
            srcWidth = bitmap.width,
            srcHeight = bitmap.height,
            dstWidth = dstWidth,
            dstHeight = dstHeight,
            scale = scale,
            maxSize = maxSize,
        ) == 1.0
    }
}

@Synchronized
    @WorkerThread
    fun hasAvailableFileDescriptors(logger: Logger?): Boolean {
        if (checkFileDescriptors()) {
            decodesSinceLastFileDescriptorCheck = 0
            lastFileDescriptorCheckTimestamp = SystemClock.uptimeMillis()

            val numUsedFileDescriptors = fileDescriptorList.list().orEmpty().count()
            hasAvailableFileDescriptors = numUsedFileDescriptors < FILE_DESCRIPTOR_LIMIT
            if (!hasAvailableFileDescriptors) {
                logger?.log(TAG, Logger.Level.Warn) {
                    "Unable to allocate more hardware bitmaps. " +
                        "Number of used file descriptors: $numUsedFileDescriptors"
                }
            }
        }
        return hasAvailableFileDescriptors
    }

@MainThread
internal suspend fun Lifecycle.awaitStarted() {
    // Fast path: we're already started.
    if (currentState.isAtLeast(STARTED)) return

    // Slow path: observe the lifecycle until we're started.
    var observer: LifecycleObserver? = null
    try {
        suspendCancellableCoroutine { continuation ->
            observer = object : DefaultLifecycleObserver {
                override fun onStart(owner: LifecycleOwner) {
                    continuation.resume(Unit)
                }
            }
            addObserver(observer)
        }
    } finally {
        // 'observer' will always be null if this method is marked as 'inline'.
        observer?.let(::removeObserver)
    }
}

override fun onTrimMemory(level: Int) = synchronized(this@AndroidSystemCallbacks) {
    withImageLoader { imageLoader ->
        imageLoader.options.logger?.log(TAG, Logger.Level.Verbose) {
            "trimMemory, level=$level"
        }

        when {
            level >= TRIM_MEMORY_BACKGROUND -> {
                // The app is in the background and is in the queue to be killed.
                imageLoader.memoryCache?.clear()
            }
            level >= TRIM_MEMORY_UI_HIDDEN -> {
                // The app is in the background.
                activityCallbacks.register(imageLoader.options.application)
            }
            level >= TRIM_MEMORY_RUNNING_LOW -> {
                // The app is in the foreground, but is running low on memory.
                imageLoader.memoryCache?.apply { trimToSize(size / 2) }
            }
        }
    }
}

@JvmOverloads
    @Suppress("UNCHECKED_CAST")
    fun newFetcher(
        data: Any,
        options: Options,
        imageLoader: ImageLoader,
        startIndex: Int = 0,
    ): Pair<Fetcher, Int>? {
        for (index in startIndex until fetcherFactories.size) {
            val (factory, type) = fetcherFactories[index]
            if (type.isInstance(data)) {
                val fetcher = (factory as Fetcher.Factory<Any>).create(data, options, imageLoader)
                if (fetcher != null) return fetcher to index
            }
        }
        return null
    }

@JvmStatic
    fun computeSizeMultiplier(
        srcWidth: Float,
        srcHeight: Float,
        dstWidth: Float,
        dstHeight: Float,
        scale: Scale,
        maxSize: Size,
    ): Float {
        val widthPercent = dstWidth / srcWidth
        val heightPercent = dstHeight / srcHeight
        var percent = when (scale) {
            Scale.FILL -> maxOf(widthPercent, heightPercent)
            Scale.FIT -> minOf(widthPercent, heightPercent)
        }
        if (maxSize.width is Dimension.Pixels) {
            val maxWidthPercent = maxSize.width.px / srcWidth
            percent = percent.coerceAtMost(maxWidthPercent)
        }
        if (maxSize.height is Dimension.Pixels) {
            val maxHeightPercent = maxSize.height.px / srcHeight
            percent = percent.coerceAtMost(maxHeightPercent)
        }
        return percent
    }

@JvmStatic
    fun computeSizeMultiplier(
        srcWidth: Double,
        srcHeight: Double,
        dstWidth: Double,
        dstHeight: Double,
        scale: Scale,
        maxSize: Size,
    ): Double {
        val widthPercent = dstWidth / srcWidth
        val heightPercent = dstHeight / srcHeight
        var percent = when (scale) {
            Scale.FILL -> maxOf(widthPercent, heightPercent)
            Scale.FIT -> minOf(widthPercent, heightPercent)
        }
        if (maxSize.width is Dimension.Pixels) {
            val maxWidthPercent = maxSize.width.px / srcWidth
            percent = percent.coerceAtMost(maxWidthPercent)
        }
        if (maxSize.height is Dimension.Pixels) {
            val maxHeightPercent = maxSize.height.px / srcHeight
            percent = percent.coerceAtMost(maxHeightPercent)
        }
        return percent
    }

@JvmStatic
    fun computeDstSize(
        srcWidth: Int,
        srcHeight: Int,
        targetSize: Size,
        scale: Scale,
        maxSize: Size,
    ): IntPair {
        var dstWidth: Int
        var dstHeight: Int
        if (targetSize.isOriginal) {
            dstWidth = srcWidth
            dstHeight = srcHeight
        } else {
            dstWidth = targetSize.width.toPx(scale)
            dstHeight = targetSize.height.toPx(scale)
        }
        if (maxSize.width is Dimension.Pixels && !dstWidth.isMinOrMax()) {
            dstWidth = dstWidth.coerceAtMost(maxSize.width.px)
        }
        if (maxSize.height is Dimension.Pixels && !dstHeight.isMinOrMax()) {
            dstHeight = dstHeight.coerceAtMost(maxSize.height.px)
        }
        return IntPair(dstWidth, dstHeight)
    }
